function:
# Drop health check logs from the main stream
if exists(.path) {
    if .path == "/health" || .path == "/healthz" || .path == "/ready" || .path == "/favicon.ico" {
        if exists(.http_status) && .http_status == 200 {
            abort
        }
    }
}

# Drop OPTIONS preflight requests
if exists(.method) && .method == "OPTIONS" {
    abort
} 
 .
